    public function handle(): int
    {
        $dry = $this->option('dry-run');
        if ($dry) {
            $this->warn('[DRY RUN] No changes will be written.');
        }

        $updated   = 0;
        $notFound  = 0;
        $isVerbose = $this->output->isVerbose();

        foreach (self::DATA as $pen => $d) {
            [$invNum, $invDate, $invAmt, $invStatus, $feePaid,
             $payDate, $amtPaid, $mop, $rp1, $rp2, $mmed, $sponsor] = $d;

            $candidate = DB::table('candidates')
                ->whereRaw('TRIM(entry_number) = ?', [trim($pen)])
                ->first();

            if (!$candidate) {
                $notFound++;
                if ($isVerbose) {
                    $this->line("  NOT FOUND: {$pen}");
                }
                continue;
            }

            if ($isVerbose) {
                $this->line("  {$pen} → inv:{$invNum} amt:{$invAmt} status:{$invStatus} paid:{$feePaid} mmed:{$mmed}");
            }

            if (!$dry) {
                $payload = [
                    'invoice_status'   => $invStatus,
                    'fee_paid'         => $feePaid,
                    'repeat_paper_one' => $rp1,
                    'repeat_paper_two' => $rp2,
                    'mmed'             => $mmed,
                ];
                if ($invNum !== null)   $payload['invoice_number']  = $invNum;
                if ($invDate !== null)  $payload['invoice_date']    = $invDate;
                if ($invAmt !== null)   $payload['invoice_amount']  = $invAmt;
                if ($payDate !== null)  $payload['payment_date']    = $payDate;
                if ($amtPaid !== null)  $payload['amount_paid']     = $amtPaid;
                if ($mop !== null)      $payload['mode_of_payment'] = $mop;
                if ($sponsor !== null)  $payload['sponsor']         = $sponsor;

                DB::table('candidates')
                    ->where('id', $candidate->id)
                    ->update($payload);
            }
            $updated++;
        }

        $this->newLine();
        $this->info('--- Summary ---');
        if ($dry) {
            $this->warn("Would update : {$updated} candidate(s)");
        } else {
            $this->info("Updated      : {$updated} candidate(s)");
        }
        $this->line("Not found    : {$notFound} PEN(s)");
        if ($notFound > 0) {
            $this->warn('Run with -v to see which PENs were not found.');
        }
        return self::SUCCESS;
    }
